#include<bits/stdc++.h>
using namespace std;
const int N=100010;
vector<pair<int,int>> mp[N],mp1[N];
int n,m,dfn[N],low[N],dis[N],sum[N],dfncnt,id[N],siz[N],scccnt;
bool instk[N],vis[N];
int x[N*2],y[N*2],z[N*2],k[N*2];
stack<int> s;
void tarjan(int x)
{
    dfn[x]=low[x]=++dfncnt;
    s.push(x);
    instk[x]=1;
    for(auto i:mp[x])
    {
        int v=i.first;
        if(dfn[v]==0)
        {
            tarjan(v);
            low[x]=min(low[x],low[v]);
        }
        else if(instk[v])
        {
            low[x]=min(low[x],dfn[v]);
        }
    }
    if(dfn[x]==low[x])
    {
        scccnt++;
        int top;
        do
        {
            top=s.top();
            instk[top]=0;
            siz[scccnt]++;
            id[top]=scccnt;
            s.pop();
        }while(top!=x);
    }
}
void spfa(int st)
{
	memset(vis,0,sizeof(vis));
    memset(dis,-0x3f,sizeof(dis));
	queue<int> q;
	q.push(st);
	dis[st]=sum[st];
	while(!q.empty())
	{
		int t=q.front();
		q.pop();
		vis[t]=0;
		for(auto i:mp1[t])
		{
			int v=i.first,val=i.second;
			if(dis[v]<dis[t]+val+sum[v])
			{
				dis[v]=dis[t]+val+sum[v];
				if(!vis[v])
				{
					vis[v]=1;
					q.push(v);
				}
			}
		}
	}
}
int main()
{
    scanf("%d%d",&n,&m);
    for(int i=1;i<=m;i++)
    {
        double tmp;
        scanf("%d%d%d%lf",&x[i],&y[i],&z[i],&tmp);
        k[i]=tmp*10;
        mp[x[i]].push_back(make_pair(y[i],z[i]));
    }
    for(int i=1;i<=n;i++)
    {
        if(!dfn[i])
        {
            tarjan(i);
        }
    }
    for(int i=1;i<=m;i++)
    {
        if(id[x[i]]==id[y[i]])
        {
            int tmp=z[i];
            while(tmp)
            {
                sum[id[x[i]]]+=tmp;
                tmp=tmp*k[i]/10;
            }
        }
        else
        {
            mp1[id[x[i]]].push_back(make_pair(id[y[i]],z[i]));
        }
    }
    int s,ans=0;
    scanf("%d",&s);
    spfa(id[s]);
    for(int i=1;i<=scccnt;i++)
    {
        ans=max(ans,dis[i]);
    }
    printf("%d",ans);
    return 0;
}
